class Solution {
    /**
     * Returns the smallest index i such that s[i] == s[n - i - 1].
     * If no such index exists, returns -1.
     * 
     * @param s The input string.
     * @return The smallest index i satisfying the condition, or -1.
     */
    public static long solve(String s) {
        int n = s.length();

        // We are looking for the minimum i >= 0 such that s[i] == s[n - i - 1].
        // Since we want the minimum i, we should iterate i starting from 0.
        // We only need to check i up to the middle of the string, as after that, 
        // the pairs (i, n - i - 1) would have already been checked or be identical.
        // The maximum meaningful i to check is floor((n - 1) / 2).

        for (int i = 0; i <= n - 1; i++) {
            int j = n - 1 - i;

            // The problem asks for the smallest i such that s[i] == s[n - i - 1].
            // We must check all possible indices i from 0 to n-1.
            // Although the indices (i, j) repeat symmetric pairs, we must return the smallest *i*.

            if (s.charAt(i) == s.charAt(j)) {
                // Since we iterate i in increasing order (0, 1, 2, ...), 
                // the first i that satisfies the condition is the smallest such i.
                return (long) i;
            }

            // Optimization: If i reaches a point where i > j, 
            // we are checking pairs we have already checked (e.g., if n=8, we check (0,7), (1,6), (2,5), (3,4), then (4,3) which is same as (3,4)).
            // However, since we are looking for the minimum *i*, stopping the loop at n/2 is safe if we only considered unique pairs.
            // But since the requirement is strictly the smallest *i* (and the definition allows i to go up to n-1), 
            // we must iterate up to n-1 to guarantee we find the smallest i if the condition holds even for i > n/2.
            // Wait, if i > n/2, then j = n - i - 1 < i. If s[i] == s[j], then s[j] == s[i]. 
            // Since j < i, we would have already found the match when checking index j earlier.
            // Therefore, we only need to check up to i = n - 1 - i, which means 2i <= n - 1, or i <= (n - 1) / 2.

            if (i > (n - 1) / 2) {
                // We have checked all unique pairs (i, n-i-1) where i <= n-i-1.
                // Any further i would have its symmetric counterpart j = n-i-1 being smaller than i,
                // and thus the match would have been found when checking index j.
                break;
            }
        }

        // If the loop completes without finding a match
        return -1L;
    }
